import React, { useState } from "react";
import { Bell, ArrowUpRight, ArrowDownLeft } from "lucide-react";
import TransactionReceiptScreen from "./TransactionReceiptScreen.jsx";
import { formatCurrency } from "../helpers/helpers";

export default function HomeScreen({ balance, savingsBalance, transactions, userName, openScreen }) {
  const [selectedTransaction, setSelectedTransaction] = useState(null);

  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 18) return "Good afternoon";
    return "Good evening";
  };

  if (selectedTransaction) {
    // Show transaction receipt screen
    return (
      <TransactionReceiptScreen
        transaction={selectedTransaction}
        goBack={() => setSelectedTransaction(null)}
      />
    );
  }

  return (
    <div className="pb-24 animate-fade-in">
      {/* Header */}
      <header className="px-6 pt-12 pb-6 flex justify-between items-center bg-white sticky top-0 z-10 shadow-sm">
        <div>
          <p className="text-gray-500 text-sm font-medium">{getGreeting()},</p>
          <h1 className="text-2xl font-bold text-gray-800">{userName}</h1>
        </div>
        <button className="p-2 bg-gray-50 rounded-full hover:bg-gray-100 transition-colors relative">
          <Bell className="w-5 h-5 text-gray-600" />
          <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
        </button>
      </header>

      {/* Total Balance Card */}
      <div className="px-6 mb-8">
        <div className="bg-gradient-to-br from-emerald-600 to-teal-800 rounded-3xl p-6 text-white shadow-lg shadow-emerald-200">
          <div className="flex justify-between items-start mb-2">
            <span className="text-emerald-100 text-sm font-medium">Balance</span>
            <span className="text-lg font-bold">Nest.</span>
          </div>
          <div className="text-4xl font-bold mb-6 tracking-tight">
            ${formatCurrency(balance)}
          </div>
          <div className="flex gap-3">
            <button
              onClick={() => openScreen("Deposit")}
              className="flex-1 bg-white/20 backdrop-blur-sm py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium hover:bg-white/30 transition-colors"
            >
              <ArrowUpRight className="w-4 h-4" /> Deposit
            </button>
            <button
              onClick={() => openScreen("Withdraw")}
              className="flex-1 bg-white/20 backdrop-blur-sm py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium hover:bg-white/30 transition-colors"
            >
              <ArrowDownLeft className="w-4 h-4" /> Withdraw
            </button>
          </div>
        </div>
      </div>

      {/* Transactions */}
      <div className="px-6">
        <div className="flex justify-between items-center mb-4">
          <h2 className="font-bold text-gray-800 text-lg">Recent Transactions</h2>
          <button
            className="text-gray-400"
            onClick={() => openScreen("Transactions")}
          >
            ▶
          </button>
        </div>
        <div className="space-y-4">
          {transactions.map((t) => (
            <div
              key={t.id}
              onClick={() => setSelectedTransaction(t)}
              className="flex items-center justify-between bg-white p-3 rounded-xl border border-gray-50 cursor-pointer hover:bg-gray-50"
            >
              <div className="flex items-center gap-3">
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center ${
                    t.type === "deposit" || t.type === "savings"
                      ? "bg-emerald-100 text-emerald-600"
                      : "bg-red-100 text-red-600"
                  }`}
                >
                  {t.type === "deposit" || t.type === "savings"
                    ? <ArrowDownLeft className="w-5 h-5" />
                    : <ArrowUpRight className="w-5 h-5" />}
                </div>
                <div>
                  <p className="font-semibold text-gray-800">{t.title}</p>
                  <p className="text-xs text-gray-400">{t.date}</p>
                </div>
              </div>
              <span
                className={`font-bold text-sm ${
                  t.type === "deposit" || t.type === "savings"
                    ? "text-emerald-600"
                    : "text-gray-800"
                }`}
              >
                {t.type === "deposit" || t.type === "savings" ? "+" : "-"}${formatCurrency(t.amount)}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
